#!/usr/bin/env bash
# us-eu.sh — 亚马逊新品上架 (US/EU 通用) SOP walkthrough for 跨境电商运营.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="跨境电商运营"
WORKFLOW="亚马逊新品上架 (US/EU 通用)"

usage() {
  cat <<EOF
us-eu.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./us-eu.sh             # interactive
  ./us-eu.sh --dry-run
  ./us-eu.sh --json
  ./us-eu.sh --explain
  ./us-eu.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "亚马逊新品上架 (US/EU 通用)" 工作流。

一句话: 从「我决定卖 X」到「listing 跑稳定单量」, 30-90 天周期

入门 SOP 共 8 步, 失败模式自检 5 项。

相关心智模型:
  • 合规优先于流量: 在欧美主流站点, 新品类上线前先解决「能不能合规开卖」, 再考虑「能不能跑出量」。
  • 选品决定 90% 命运: 在亚马逊体系里, 一个品的最终成败 90% 在选品阶段已经决定, 后续运营只能放大这 10% 空间。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "完成 Brand Registry 品牌备案 — 没备案 A+ Content / Brand Analytics / Sponsored Brands 全锁死"
  "关键词调研 — 用 Helium 10 Cerebro 反查 top 5 同类 ASIN, 整理 30-50 个 long-tail 词"
  "Listing 撰写 — 标题 / 5 个 bullet point / Description / A+ Content 七模块"
  "首批 FBA 入仓 — 算清楚海运周期 (45-60 天) + 头程 + 入仓时间"
  "冷启动期 PPC — Auto + Manual 双轨, 预算 \$30-50/天/SKU 起步"
  "Vine 报名 — 30 个免费评价, 大幅提升早期信任度"
  "每日监控 — Search Query Performance 看流量结构 + ACOS"
  "30 天复盘 — BSR / 评价 / ACOS / 退货率 四维度判断是否优化 / 加预算 / 砍"
)
declare -a FAILURE_MODES=(
  "没做 Brand Registry 直接上, 转化率低后再补已晚"
  "关键词只用一家工具, 数据偏差大"
  "A+ Content 用 AI 生成不加真实场景, 转化率反不如 plain text"
  "冷启动期 ACOS 慌乱, 提前停广告导致系统刚找到人群就被打断"
  "旺季前 (Q4) 备货不足或过度"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "us-eu-walkthrough"
fi
